@PostConstruct
public void configureWireMock() throws IOException {
    WireMockServer server = new WireMockServer(wireMockConfig().port(8085));

    // Lê o arquivo com a lista de CEPs
    ClassPathResource resource = new ClassPathResource("wiremock/files/cep.json");
