package com.example.cepapi.service;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;

import com.example.cepapi.entity.CepLog;
import com.example.cepapi.repository.CepLogRepository;

import java.time.LocalDateTime;

import java.util.List;

@Service
public class CepService {

    @Value("${cep.api.url}")
    private String apiUrl;

    private final RestTemplate restTemplate = new RestTemplate();

    private final CepLogRepository cepLogRepository;

    public CepService(CepLogRepository cepLogRepository) {
        this.cepLogRepository = cepLogRepository;
    }

    public String getCepInfo(String cep) {
        // apiUrl é http://localhost:8085/cep
        // urlFinal fica http://localhost:8085/cep?cep=12345-678
        String urlFinal = apiUrl + "?cep=" + cep;

        try {
            String response = restTemplate.getForObject(urlFinal, String.class);
            // Assume que o JSON já está no formato correto e não é necessário parsing adicional.

            // Salvar entrada de log
            CepLog logEntry = new CepLog();
            logEntry.setTimestamp(LocalDateTime.now());
            logEntry.setCep(cep);
            logEntry.setResponse(response);
            cepLogRepository.save(logEntry);

            return response;
        } catch (Exception e) {
            // Tratar qualquer exceção que possa ocorrer durante a requisição HTTP
            throw new RuntimeException("Falha ao buscar informações de CEP", e);
        }
    }

    public List<CepLog> getAllLogs() {
        return cepLogRepository.findAll();
    }
}
