        ObjectMapper mapper = new ObjectMapper();
        JsonNode rootNode = mapper.readTree(jsonData);

        if (rootNode.isArray()) {
            for (JsonNode node : rootNode) {
                String cep = node.get("cep").asText();

                // Cria um stub específico para este CEP
                server.stubFor(WireMock.get(WireMock.urlPathEqualTo("/cep"))
                        .withQueryParam("cep", WireMock.equalTo(cep))
                        .willReturn(WireMock.aResponse()
                                .withStatus(200)
                                .withHeader("Content-Type", "application/json")
                                .withBody(node.toString()))); // Retorna apenas o objeto do CEP
            }
        }

        return server;
    }
}
